import{_ as e,c as i,o as a,ag as n}from"./chunks/framework.BgId8OS5.js";const u=JSON.parse('{"title":"Lint integration","description":"","frontmatter":{},"headers":[],"relativePath":"docs/integrations/lint.md","filePath":"docs/integrations/lint.md"}'),s={name:"docs/integrations/lint.md"};function o(r,t,l,d,c,h){return a(),i("div",null,t[0]||(t[0]=[n('<h1 id="lint-integration" tabindex="-1">Lint integration <a class="header-anchor" href="#lint-integration" aria-label="Permalink to &quot;Lint integration&quot;">​</a></h1><p>Knowing when to run Prettier, ESLint or any other tool is not always straight-forward. In most cases, your IDE does that stuff for you, resulting in unnecessarily running the tools manually. Compas integrates with ESLint and Prettier to add a custom action when there are files available to be linted.</p><h2 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h2><p>Compas automatically enables this integration when it detects that ESLint and/or Prettier is installed.</p><p>Compas can add <code>@compas/eslint-plugin</code> as a development dependency when you run:</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">compas</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lint</span></span></code></pre></div><p><code>@compas/eslint-plugin</code> includes ESLint, Prettier, various plugins for the aforementioned, so you don&#39;t have to install them all separately. It also contains some custom ESLint rules and default configs for both ESLint and Prettier.</p><h2 id="config" tabindex="-1">Config <a class="header-anchor" href="#config" aria-label="Permalink to &quot;Config&quot;">​</a></h2><p>When <code>@compas/eslint-plugin</code> is installed and no config file is present for ESLint and Prettier, Compas will automatically supply the necessary config files. You can override this behavior by manually creating the config files.</p><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>Compas assumes that the tools only ever run from the top most projects. Most lint tools support using varying configs in different directories to alter behavior in for example workspaces.</li></ul>',11)]))}const g=e(s,[["render",o]]);export{u as __pageData,g as default};
